  ('2d08af6c-7b92-421c-8e92-306ba6a8919a', $$Scheikunde$$, $$VWO$$, $$Cadmiumgeel$$, $$VWO Scheikunde 2022-II$$),
  ('1c3f1b7f-912a-4434-9da3-ea61b094ebc5', $$Scheikunde$$, $$VWO$$, $$Merox$$, $$VWO Scheikunde 2022-II$$),
  ('f6976031-cb1b-4033-bd02-2c0d2e850dc1', $$Scheikunde$$, $$VWO$$, $$EPDM-rubber$$, $$VWO Scheikunde 2022-II$$),
