   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag4.png$$, $$Geef de vergelijking van de omzetting van cadmiumgeel tot cadmiumsulfaatmonohydraat.$$, array['2db34045-3641-43c2-851e-109cf4aaaabd']::uuid[]),
  ('f3f686c8-f371-40c9-94d9-45b1386dcf62', '2d08af6c-7b92-421c-8e92-306ba6a8919a', 5,
