   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag9.png$$, $$Geef de vergelijking van de reactie die verloopt in R2.$$, array['e3b3c353-7612-4046-8395-8293a442f4db', 'ef73cc77-9a9b-4a9c-9f17-a5e16528718d']::uuid[]),
  ('ee5b4ca8-4732-446b-8fed-38f2fe5b4302', '1c3f1b7f-912a-4434-9da3-ea61b094ebc5', 10,
