   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag11.png$$, $$Leg uit welke bewerking het natronloog moet ondergaan voordat het kan worden teruggevoerd.$$, array['5df2796e-998b-4428-a369-d7332ee5d896']::uuid[]),
