   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag15.png$$, $$Leg uit dat t-EPDM met een groot percentage kristallijne gebieden een kleinere vervormbaarheid heeft dan t-EPDM met een klein percentage kristallijne gebieden. Gebruik hierbij begrippen op microniveau.$$, array['40e2e847-0844-4daa-ba50-463d4853dcf3', '1fc7d809-f598-4c41-bb9b-cf9c4cbb5f0d']::uuid[]),
  ('33772032-bf2f-48f8-8b45-7ae82735e0b5', 'f6976031-cb1b-4033-bd02-2c0d2e850dc1', 16,
