   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag16.png$$, $$Leg uit of het gehalte ¹⁴C in Keltan®-Eco hoger of lager is dan in EPDM-rubber dat is geproduceerd op basis van fossiele grondstoffen.$$, array['c0ef24b4-029c-41ba-91c4-e5e31e38e989', 'bb42ac54-a32f-4e03-8670-ea64db2b3af0']::uuid[]),
