   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag20.png$$, $$Leg uit, aan de hand van deze gegevens, of door deze omzetting de primaire structuur van de peptideketens in de eiwitten verloren gaat.$$, array['2e6742d6-0da6-49d5-9ff0-9c3503081abb']::uuid[]),
