   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag21.png$$, $$Geef de formule van het deeltje X.$$, array['4ec3145d-30bc-4f51-9216-93d0e72ae8da']::uuid[]),
