− Geef links van de pijl met pijlen weer hoe elektronenparen worden verplaatst tijdens deze reactie.$$, array['9ba92634-0c1a-4e77-8d82-7858a5a4a793', '76bff4c7-8308-452e-aa7d-e9cafa194f9c']::uuid[]);
